import React, { useEffect, useMemo, useState } from 'react';
import ListingCard from '../components/ListingCard';
import { createListing, fetchListings } from '../utils';

const initialForm = {
  title: '',
  description: '',
  price: '',
  category: 'General',
  location: '',
  sellerId: 'user-1',
};

function Listings() {
  const [listings, setListings] = useState([]);
  const [filters, setFilters] = useState({ q: '', location: '', category: '' });
  const [form, setForm] = useState(initialForm);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [status, setStatus] = useState('');

  useEffect(() => {
    let active = true;

    async function loadListings() {
      setLoading(true);
      setError('');
      try {
        const data = await fetchListings(filters);
        if (active) {
          setListings(data);
        }
      } catch (err) {
        if (active) {
          setError('Unable to load listings. Start the backend on port 5000.');
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    loadListings();
    return () => {
      active = false;
    };
  }, [filters]);

  const listingCountLabel = useMemo(() => {
    if (loading) {
      return 'Loading listings...';
    }
    return `${listings.length} listing${listings.length === 1 ? '' : 's'} found`;
  }, [listings.length, loading]);

  async function handleSubmit(event) {
    event.preventDefault();
    setStatus('');
    setError('');

    try {
      await createListing({
        ...form,
        price: Number(form.price),
      });
      setForm(initialForm);
      setStatus('Listing created.');
      const data = await fetchListings(filters);
      setListings(data);
    } catch (err) {
      setError('Unable to create listing. Check the form fields and backend status.');
    }
  }

  return (
    <main className="page">
      <section className="panel section">
        <span className="eyebrow">Marketplace feed</span>
        <h2 className="section-title">Listings</h2>
        <p className="muted">{listingCountLabel}</p>
        <div className="toolbar">
          <div className="field">
            <label htmlFor="search">Search</label>
            <input
              id="search"
              value={filters.q}
              onChange={(event) => setFilters((current) => ({ ...current, q: event.target.value }))}
              placeholder="fridge, lamp, textbook"
            />
          </div>
          <div className="field">
            <label htmlFor="location">Location</label>
            <input
              id="location"
              value={filters.location}
              onChange={(event) => setFilters((current) => ({ ...current, location: event.target.value }))}
              placeholder="Cambridge"
            />
          </div>
          <div className="field">
            <label htmlFor="category">Category</label>
            <select
              id="category"
              value={filters.category}
              onChange={(event) => setFilters((current) => ({ ...current, category: event.target.value }))}
            >
              <option value="">All categories</option>
              <option value="Appliances">Appliances</option>
              <option value="Furniture">Furniture</option>
              <option value="General">General</option>
            </select>
          </div>
          <div className="button-row">
            <button className="button-secondary" type="button" onClick={() => setFilters({ q: '', location: '', category: '' })}>
              Reset filters
            </button>
          </div>
        </div>

        {error ? <div className="status error">{error}</div> : null}
        {status ? <div className="status success">{status}</div> : null}

        <div className="cards" style={{ marginTop: 20 }}>
          {!loading && listings.length === 0 ? (
            <div className="empty-state">No listings match the current filters.</div>
          ) : null}
          {listings.map((listing) => (
            <ListingCard key={listing.id} listing={listing} />
          ))}
        </div>
      </section>

      <section className="panel section">
        <span className="eyebrow">Create listing</span>
        <h2 className="section-title">Post something for sale</h2>
        <form className="form-grid" onSubmit={handleSubmit}>
          <div className="field">
            <label htmlFor="title">Title</label>
            <input
              id="title"
              value={form.title}
              onChange={(event) => setForm((current) => ({ ...current, title: event.target.value }))}
              required
            />
          </div>
          <div className="field">
            <label htmlFor="description">Description</label>
            <textarea
              id="description"
              value={form.description}
              onChange={(event) => setForm((current) => ({ ...current, description: event.target.value }))}
              required
            />
          </div>
          <div className="toolbar">
            <div className="field">
              <label htmlFor="price">Price</label>
              <input
                id="price"
                type="number"
                min="0"
                step="0.01"
                value={form.price}
                onChange={(event) => setForm((current) => ({ ...current, price: event.target.value }))}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="form-category">Category</label>
              <select
                id="form-category"
                value={form.category}
                onChange={(event) => setForm((current) => ({ ...current, category: event.target.value }))}
              >
                <option value="General">General</option>
                <option value="Appliances">Appliances</option>
                <option value="Furniture">Furniture</option>
              </select>
            </div>
            <div className="field">
              <label htmlFor="form-location">Location</label>
              <input
                id="form-location"
                value={form.location}
                onChange={(event) => setForm((current) => ({ ...current, location: event.target.value }))}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="seller-id">Seller</label>
              <select
                id="seller-id"
                value={form.sellerId}
                onChange={(event) => setForm((current) => ({ ...current, sellerId: event.target.value }))}
              >
                <option value="user-1">alex.chen</option>
              </select>
            </div>
          </div>
          <div className="button-row">
            <button className="button" type="submit">
              Publish listing
            </button>
          </div>
        </form>
      </section>
    </main>
  );
}

export default Listings;
